import { readFile, writeFile } from "node:fs/promises";

const outputPath = "docs/dependency-inventory.md";
const verifyOnly = process.argv.includes("--verify");

const rootPackage = JSON.parse(await readFile("package.json", "utf8"));
const frontendPackage = JSON.parse(await readFile("frontend/package.json", "utf8"));

const inventory = [
  "# Dependency Inventory",
  "",
  "Generated by `node scripts/dependency-inventory.mjs`.",
  "",
  "## Runtime Dependencies",
  "",
  "| Module | Dependency | Purpose | License | Security impact | Operational impact |",
  "|---|---|---|---|---|---|",
  ...rows("frontend", frontendPackage.dependencies, {
    react: "Frontend UI runtime",
    "react-dom": "Browser rendering for React",
    vite: "Frontend build and local development server",
    typescript: "Type checking for frontend contracts",
    "@vitejs/plugin-react": "React integration for Vite"
  }),
  "",
  "## Development and Test Dependencies",
  "",
  "| Module | Dependency | Purpose | License | Security impact | Operational impact |",
  "|---|---|---|---|---|---|",
  ...rows("root", rootPackage.devDependencies, {
    prettier: "Repository formatting checks"
  }),
  ...rows("frontend", frontendPackage.devDependencies, {
    "@eslint/js": "JavaScript linting rules",
    "@testing-library/jest-dom": "DOM assertions for frontend tests",
    "@testing-library/react": "React component test helpers",
    "@types/react": "React TypeScript types",
    "@types/react-dom": "React DOM TypeScript types",
    eslint: "Frontend linting",
    globals: "Browser global definitions for linting",
    jsdom: "DOM runtime for component tests",
    vitest: "Frontend unit-test framework",
    "typescript-eslint": "TypeScript linting support"
  }),
  ...mavenRows(),
  ...internalModuleRows(),
  ""
].join("\n");

if (verifyOnly) {
  const existing = await readFile(outputPath, "utf8").catch(() => "");
  if (existing !== inventory) {
    console.error(`${outputPath} is out of date. Run node scripts/dependency-inventory.mjs.`);
    process.exit(1);
  }
} else {
  await writeFile(outputPath, inventory);
  console.log(`Wrote ${outputPath}`);
}

function rows(moduleName, dependencies = {}, purposes) {
  return Object.keys(dependencies)
    .sort()
    .map((dependency) => {
      const purpose = purposes[dependency] ?? "Project tooling";
      return `| ${moduleName} | \`${dependency}\` | ${purpose} | See package metadata | Limited to local development/CI supply chain risk | Installed by npm for local and CI checks |`;
    });
}

function mavenRows() {
  return [
    "| Maven | `org.junit:junit-bom` / `org.junit.jupiter:junit-jupiter` | Java unit-test framework | EPL-2.0 | Test-only supply chain risk | Used by Maven test phase |",
    "| Maven | `com.tngtech.archunit:archunit-junit5` | Architecture dependency tests | Apache-2.0 | Test-only supply chain risk | Used by Maven test phase |",
    "| Maven plugin | `com.diffplug.spotless:spotless-maven-plugin` | Java and POM formatting checks | Apache-2.0 | Build-plugin supply chain risk | Used by Maven format checks |",
    "| Maven plugin | `org.apache.maven.plugins:maven-dependency-plugin` | Java dependency resolution and tree scanning | Apache-2.0 | Build-plugin supply chain risk | Used by dependency scan checks |",
    "| GitHub Action | `actions/dependency-review-action` | Pull-request dependency vulnerability review | MIT | CI supply chain risk | Runs only in pull-request checks |"
  ];
}

function internalModuleRows() {
  return [
    "| Internal module | `adapters -> domain` | Keeps serialization schema access separate from pure domain contracts | Internal project code | No third-party supply chain impact | Built in the Maven reactor |",
    "| Internal module | `architecture-tests -> domain/adapters/backend/contracts` | Verifies module dependency boundaries and forbidden integration markers | Internal project code | No third-party supply chain impact | Used by Maven test phase |"
  ];
}
